1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	}
7	
8	interface QuoteStep {
9	  items: Item[];
10	}
11	
12	interface Customer {
13	  yearsWithMHPCO: number;
14	}
15	
16	const PROCESSING_FEE = 5;
17	const FIRST_INSURANCE_SURCHARGE = 0.1;
18	const CURSE_SURCHARGE = 0.5;
19	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
20	const HIGH_ENCHANTMENT_THRESHOLD = 5;
21	const LOYALTY_DISCOUNT = 0.2;
22	const LOYALTY_THRESHOLD_YEARS = 2;
23	const FOLLOWUP_DISCOUNT = 0.15;
24	
25	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
26	  sword: 100,
27	  amulet: 60,
28	  staff: 80,
29	  potion: 40,
30	};
31	
32	const COMPONENT_TYPES = ["rune", "moonstone"];
33	const COMPONENT_PREMIUM = 25;
34	const BLOCK_SIZE = 3;
35	const BLOCK_PREMIUM = 60;
36	
37	// Sum `valueOf` applied to each element of an iterable.
38	const sumOf = <T>(values: Iterable<T>, valueOf: (value: T) => number): number => {
39	  let sum = 0;
40	  for (const value of values) sum += valueOf(value);
41	  return sum;
42	};
43	
44	const isComponent = (item: Item): boolean =>
45	  COMPONENT_TYPES.includes(item.type);
46	
47	const isMainItem = (item: Item): boolean => !isComponent(item);
48	
49	// A group of exactly BLOCK_SIZE alike components is priced at the discounted
50	// BLOCK_PREMIUM; any other count is priced per component.
51	const componentGroupBasePremium = (count: number): number =>
52	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
53	
54	// An item-specific surcharge adds `rate` of the item's base premium when its
55	// condition holds, and nothing otherwise.
56	const surchargeWhen = (item: Item, applies: boolean, rate: number): number =>
57	  applies ? rate * basePremiumForItem(item) : 0;
58	
59	// Cursed items add a surcharge equal to CURSE_SURCHARGE of their base premium.
60	const curseSurcharge = (item: Item): number =>
61	  surchargeWhen(item, item.cursed ?? false, CURSE_SURCHARGE);
62	
63	// Highly enchanted items (enchantment at or above the threshold) add a
64	// surcharge equal to HIGH_ENCHANTMENT_SURCHARGE of their base premium.
65	const highEnchantmentSurcharge = (item: Item): number =>
66	  surchargeWhen(
67	    item,
68	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
69	    HIGH_ENCHANTMENT_SURCHARGE,
70	  );
71	
72	// Collapse floating-point artifacts (e.g. 197.49999999) before rounding, so we
73	// never round a value that is only spuriously above or below a whole number.
74	const collapseFloatArtifacts = (amount: number): number =>
75	  Number(amount.toFixed(6));
76	
77	// Premiums are rounded UP, in MHPCO's favor.
78	const roundUpInMHPCOsFavor = (amount: number): number =>
79	  Math.ceil(collapseFloatArtifacts(amount));
80	
81	// Payouts are rounded DOWN, in MHPCO's favor.
82	const roundDownInMHPCOsFavor = (amount: number): number =>
83	  Math.floor(collapseFloatArtifacts(amount));
84	
85	// Look up a per-type value, treating an unknown type as contributing nothing.
86	const valueByType = (table: Record<string, number>, type: string): number =>
87	  table[type] ?? 0;
88	
89	const basePremiumForItem = (item: Item): number =>
90	  valueByType(BASE_PREMIUM_BY_TYPE, item.type);
91	
92	// Each main item is priced on its own.
93	const mainItemsBasePremium = (items: Item[]): number =>
94	  sumOf(items, basePremiumForItem);
95	
96	// Tally how many values fall under each key, where the key is read off each
97	// value by `keyOf`.
98	const countBy = <T>(values: Iterable<T>, keyOf: (value: T) => string): Map<string, number> => {
99	  const counts = new Map<string, number>();
100	  for (const value of values) {
101	    const key = keyOf(value);
102	    counts.set(key, (counts.get(key) ?? 0) + 1);
103	  }
104	  return counts;
105	};
106	
107	const countByType = (items: Item[]): Map<string, number> =>
108	  countBy(items, (item) => item.type);
109	
110	// Components are grouped by type, and each group is block-priced.
111	const componentsBasePremium = (components: Item[]): number =>
112	  sumOf(countByType(components).values(), componentGroupBasePremium);
113	
114	const policyBasePremium = (items: Item[]): number =>
115	  mainItemsBasePremium(items.filter(isMainItem)) +
116	  componentsBasePremium(items.filter(isComponent));
117	
118	// Tier 1 — item-specific surcharges: computed off each affected item's base
119	// premium and summed across the policy. (e.g. curse; later high-enchantment.)
120	const itemSurcharges = (items: Item[]): number =>
121	  sumOf(items, (item) => curseSurcharge(item) + highEnchantmentSurcharge(item));
122	
123	// A policy-wide modifier adds `rate` of the policy base premium when its
124	// condition holds, and nothing otherwise.
125	const fractionOfPolicyBaseWhen = (
126	  policyBase: number,
127	  applies: boolean,
128	  rate: number,
129	): number => (applies ? rate * policyBase : 0);
130	
131	// Every new policy carries a surcharge equal to FIRST_INSURANCE_SURCHARGE of
132	// the policy base premium. It always applies, so it is computed directly
133	// rather than going through the conditional fractionOfPolicyBaseWhen helper.
134	const firstInsuranceSurcharge = (policyBase: number): number =>
135	  FIRST_INSURANCE_SURCHARGE * policyBase;
136	
137	// Long-standing customers (at or above the loyalty threshold) receive a
138	// discount equal to LOYALTY_DISCOUNT of the policy base premium.
139	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
140	  fractionOfPolicyBaseWhen(
141	    policyBase,
142	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
143	    LOYALTY_DISCOUNT,
144	  );
145	
146	// Every contract after the customer's first (a non-zero quote index) receives a
147	// discount equal to FOLLOWUP_DISCOUNT of the policy base premium.
148	const followUpDiscount = (policyBase: number, quoteIndex: number): number =>
149	  fractionOfPolicyBaseWhen(policyBase, quoteIndex >= 1, FOLLOWUP_DISCOUNT);
150	
151	// Tier 2 — policy-wide modifiers: each computed as a fraction of the policy
152	// base premium. Surcharges add; discounts subtract. (first-insurance surcharge,
153	// loyalty discount, follow-up discount.)
154	const policyWideModifiers = (
155	  policyBase: number,
156	  customer: Customer,
157	  quoteIndex: number,
158	): number =>
159	  firstInsuranceSurcharge(policyBase) -
160	  loyaltyDiscount(policyBase, customer) -
161	  followUpDiscount(policyBase, quoteIndex);
162	
163	export const quote = (
164	  customer: Customer,
165	  step: QuoteStep,
166	  quoteIndex: number,
167	): number => {
168	  const policyBase = policyBasePremium(step.items);
169	
170	  const total =
171	    policyBase +
172	    itemSurcharges(step.items) +
173	    policyWideModifiers(policyBase, customer, quoteIndex) +
174	    PROCESSING_FEE;
175	  return roundUpInMHPCOsFavor(total);
176	};
177	
178	interface Damage {
179	  itemType: string;
180	  amount: number;
181	}
182	
183	interface Incident {
184	  cause: string;
185	  damages: Damage[];
186	}
187	
188	interface ClaimResult {
189	  payout: number;
190	  remainingCap: number;
191	}
192	
193	const DEDUCTIBLE = 100;
194	const ENCHANTMENT_HALF_THRESHOLD = 8;
195	const HALF_REIMBURSEMENT = 0.5;
196	const CAP_MULTIPLIER = 2;
197	const COMPONENT_INSURANCE_VALUE = 250;
198	
199	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
200	  sword: 1000,
201	  amulet: 600,
202	  staff: 800,
203	  potion: 400,
204	};
205	
206	// Each item is insured for a fixed value; components share a flat value.
207	const insuranceValueForItem = (item: Item): number =>
208	  isComponent(item)
209	    ? COMPONENT_INSURANCE_VALUE
210	    : valueByType(INSURANCE_VALUE_BY_TYPE, item.type);
211	
212	const insuranceSum = (items: Item[]): number =>
213	  sumOf(items, insuranceValueForItem);
214	
215	// A policy's total payout cap is a fixed multiple of the insured value of its
216	// items. Premium-side modifiers (block discounts, surcharges) do not affect it.
217	const payoutCap = (policyItems: Item[]): number =>
218	  CAP_MULTIPLIER * insuranceSum(policyItems);
219	
220	// Items at or above the half-reimbursement enchantment threshold are reimbursed
221	// at only half the damage amount.
222	const isHalfReimbursed = (item: Item | undefined): boolean =>
223	  (item?.enchantment ?? 0) >= ENCHANTMENT_HALF_THRESHOLD;
224	
225	// What MHPCO reimburses for a single damage, before the deductible.
226	// Reimbursement turns solely on enchantment: high-enchantment items
227	// (at or above the threshold) get half the damage amount; everything else
228	// gets the full amount. Material is not inspected — dragon material is
229	// fully reimbursed simply because it falls in the full-amount branch, and
230	// half-reimbursement still wins for a high-enchantment dragon item.
231	const reimbursedAmount = (item: Item | undefined, amount: number): number =>
232	  isHalfReimbursed(item) ? HALF_REIMBURSEMENT * amount : amount;
233	
234	// A damage is reimbursed against the first policy item of its type.
235	const itemForDamage = (policyItems: Item[], damage: Damage): Item | undefined =>
236	  policyItems.find((item) => item.type === damage.itemType);
237	
238	// The net payout for a single damage: what MHPCO reimburses for the damaged
239	// item, less the per-damage deductible.
240	const netPayoutForDamage = (policyItems: Item[], damage: Damage): number =>
241	  reimbursedAmount(itemForDamage(policyItems, damage), damage.amount) -
242	  DEDUCTIBLE;
243	
244	// A claim is rejected if it reports more damages of a given type than the
245	// policy actually covers. This also rejects damage to an item type absent
246	// from the policy: its insured count is 0, so any such damage over-claims.
247	const rejectIfOverClaimed = (policyItems: Item[], incident: Incident): void => {
248	  const insuredCounts = countByType(policyItems);
249	  const damageCounts = countBy(incident.damages, (damage) => damage.itemType);
250	  for (const [type, count] of damageCounts) {
251	    if (count > (insuredCounts.get(type) ?? 0)) {
252	      throw new Error(`Claim rejected: more ${type} damages than insured`);
253	    }
254	  }
255	};
256	
257	// A claim is rejected if any damage reports a negative amount.
258	const rejectIfNegativeDamage = (incident: Incident): void => {
259	  if (incident.damages.some((damage) => damage.amount < 0)) {
260	    throw new Error("Claim rejected: negative damage amount");
261	  }
262	};
263	
264	export const claim = (
265	  policyItems: Item[],
266	  incident: Incident,
267	  startingRemainingCap: number = payoutCap(policyItems),
268	): ClaimResult => {
269	  rejectIfOverClaimed(policyItems, incident);
270	  rejectIfNegativeDamage(incident);
271	
272	  const rawPayout = sumOf(incident.damages, (damage) =>
273	    netPayoutForDamage(policyItems, damage),
274	  );
275	  // The payout is capped at whatever remains of the policy's payout cap.
276	  const payout = roundDownInMHPCOsFavor(
277	    Math.min(rawPayout, startingRemainingCap),
278	  );
279	  return { payout, remainingCap: startingRemainingCap - payout };
280	};
